// frontend/src/App.js
import { BrowserRouter, Routes, Route, Link, Navigate } from "react-router-dom";
import { AuthProvider, useAuth, hasRole } from "./AuthContext";
import { PrivateRoute, RoleGuard } from "./routeGuards";
import Login from "./components/Login";

function Home() {
    const { user, logout } = useAuth();
    const isAdmin = hasRole(user, "ADMIN");
    const isSales = hasRole(user, "SALES");
    const isAccountant = hasRole(user, "ACCOUNTANT");

    return (
        <div style={{ padding: 16 }}>
            <h2>Trang chủ</h2>
            {user ? (
                <>
                    <p>Hello, <b>{user.username}</b></p>
                    <p>Roles: {user.roles?.join(", ")}</p>
                    <button onClick={logout}>Đăng xuất</button>
                </>
            ) : (
                <p>Chưa đăng nhập</p>
            )}

            <nav style={{ marginTop: 12 }}>
                <Link to="/">Home</Link>
                {isAdmin && <> | <Link to="/users">Users</Link></>}
                {(isAdmin || isSales) && <> | <Link to="/customers">Customers</Link></>}
                {(isAdmin || isSales) && <> | <Link to="/contracts">Contracts</Link></>}
                {(isAdmin || isAccountant) && <> | <Link to="/payments">Payments</Link></>}
                <> | <Link to="/login">Login</Link></>
            </nav>
        </div>
    );
}

// pages mẫu + gọi API thật
import { useEffect, useState } from "react";
import api from "./api";

function Users() {
    const [items, setItems] = useState([]);
    useEffect(() => {
        api.get("/api/users").then(r => setItems(r.data)).catch(console.error);
    }, []);
    return (
        <div style={{ padding: 16 }}>
            <h3>User Management</h3>
            <ul>{items.map(u => <li key={u.id}>{u.username} – {u.role?.name || u.role}</li>)}</ul>
        </div>
    );
}
function Customers() {
    const [items, setItems] = useState([]);
    useEffect(() => {
        api.get("/api/customers").then(r => setItems(r.data)).catch(console.error);
    }, []);
    return (
        <div style={{ padding: 16 }}>
            <h3>Customers</h3>
            <ul>{items.map(c => <li key={c.id}>{c.name}</li>)}</ul>
        </div>
    );
}
const Contracts = () => <div style={{ padding: 16 }}><h3>Contracts</h3></div>;
const Payments  = () => <div style={{ padding: 16 }}><h3>Payments</h3></div>;
const Forbidden = () => <div style={{ padding: 16 }}><h3>403 - Không có quyền truy cập</h3><Link to="/">Home</Link></div>;
const NotFound  = () => <div style={{ padding: 16 }}><h3>404</h3><Link to="/">Home</Link></div>;

export default function App() {
    return (
        <AuthProvider>
            <BrowserRouter>
                <Routes>
                    {/* public */}
                    <Route path="/login" element={<Login />} />

                    {/* protected */}
                    <Route path="/" element={<PrivateRoute><Home /></PrivateRoute>} />
                    <Route path="/users" element={
                        <PrivateRoute>
                            <RoleGuard roles={["ADMIN"]}><Users /></RoleGuard>
                        </PrivateRoute>
                    }/>
                    <Route path="/customers" element={
                        <PrivateRoute>
                            <RoleGuard roles={["ADMIN","SALES"]}><Customers /></RoleGuard>
                        </PrivateRoute>
                    }/>
                    <Route path="/contracts" element={
                        <PrivateRoute>
                            <RoleGuard roles={["ADMIN","SALES"]}><Contracts /></RoleGuard>
                        </PrivateRoute>
                    }/>
                    <Route path="/payments" element={
                        <PrivateRoute>
                            <RoleGuard roles={["ADMIN","ACCOUNTANT"]}><Payments /></RoleGuard>
                        </PrivateRoute>
                    }/>
                    <Route path="/403" element={<Forbidden />} />
                    <Route path="*" element={<NotFound />} />
                </Routes>
            </BrowserRouter>
        </AuthProvider>
    );
}
